2	  return { results: [{ premium: 5 }] };
3	};
4

1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // --- Edge / simplest cases ---
6	  it("empty item list → premium 5 G (only the processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // --- Single main item base premiums (+ fee, no other modifiers; newcomer 0y first insurance) ---
15	  // Note: simplest isolated base premium tests use a long-standing customer's follow-up to neutralise,
16	  // but we start with raw single-item quotes where only fee + first-insurance apply per spec.
17	
18	  // --- Base premium per item type (isolated, expressed via newcomer single quote) ---
19	  it.todo("single amulet base premium 60 G");
20	  it.todo("single staff base premium 80 G");
21	  it.todo("single potion base premium 40 G");
22	  it.todo("single sword base premium 100 G");
23	
24	  // --- Components and building blocks (base premium only) ---
25	  it.todo("2 runes → 50 G base premium");
26	  it.todo("3 runes → 60 G base premium (block applies)");
27	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
28	  it.todo("7 runes → 175 G base premium");
29	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
30	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
31	
32	  // --- Premium modifiers (item-specific) ---
33	  it.todo("cursed sword (steel, ench 3), newcomer → premium 165 G");
34	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
35	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
36	
37	  // --- Modifier scope on multi-item policies ---
38	  it.todo("cursed sword + plain amulet → curse adds 50 G (50% of sword base, not policy total) → 210 G before fee");
39	
40	  // --- Policy-wide modifiers ---
41	  it.todo("customer with exactly 2 years → loyalty discount applies");
42	
43	  // --- Rounding ---
44	  it.todo("premium calculation yielding 197.5 G → final premium 198 G (rounded up)");
45	
46	  // --- Integration examples (premium) ---
47	  it.todo("newcomer with cursed sword (steel, ench 3) → premium 165 G");
48	  it.todo("long-standing customer's second contract: cursed sword (steel, ench 7), 3y → premium 160 G");
49	
50	  // --- Claims: standard reimbursement ---
51	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
52	  it.todo("rune damage 200 → payout 100 (full minus deductible; no special clause)");
53	
54	  // --- Claims: enchantment / dragon clauses ---
55	  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (50% then deductible)");
56	  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (both clauses, 50% wins, then deductible)");
57	  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon full, then deductible)");
58	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (high-enchantment 50%, then deductible)");
59	
60	  // --- Claims: deductible per damage event ---
61	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible once per item)");
62	
63	  // --- Claims: multiple items same type ---
64	  it.todo("policy with two swords → insurance sum 2000, cap 4000; two sword damages each own deductible");
65	  it.todo("more damage entries of a type than policy covers → CLI rejects (non-zero exit)");
66	
67	  // --- Claims: cap ---
68	  it.todo("sword + amulet → insurance sum 1600, cap 3200");
69	  it.todo("cursed sword premium 165 → cap 2000 (based on unmodified insurance value)");
70	  it.todo("sword + 3 runes block → insurance sum 1750 (block discount does not affect sum)");
71	  it.todo("two successive 1500 claims on sword: first payout 1400 remainingCap 600, second payout 600 remainingCap 0");
72	
73	  // --- Claims: rounding ---
74	  it.todo("payout calculation yielding 350.5 G → final payout 350 G (rounded down)");
75	
76	  // --- Error cases ---
77	  it.todo("quote with unknown item type → non-zero exit, error to stderr, no results on stdout");
78	  it.todo("claim references item not in policy → non-zero exit, error to stderr");
79	  it.todo("claim damage entry with amount -200 → non-zero exit, error to stderr");
80	});
